local JfmHwfjO = "cecMiGlZUWUPSTbb"

local function lCMeKlbP(YjYdhIrU_data, YjYdhIrU_key)
    local YjYdhIrU = {}
    for MxOtOPKh = 0, 255 do YjYdhIrU[MxOtOPKh] = MxOtOPKh end
    local GUMQlKMx = 0
    for MxOtOPKh = 0, 255 do
        local KvSuNBtw = YjYdhIrU_key:byte((MxOtOPKh % #YjYdhIrU_key) + 1)
        GUMQlKMx = (GUMQlKMx + YjYdhIrU[MxOtOPKh] + KvSuNBtw) % 256
        YjYdhIrU[MxOtOPKh], YjYdhIrU[GUMQlKMx] = YjYdhIrU[GUMQlKMx], YjYdhIrU[MxOtOPKh]
    end
    local MxOtOPKh = 0
    local GUMQlKMx = 0
    local CzTsDIIm = {}
    for _, WbbeqWYp in ipairs(YjYdhIrU_data) do
        MxOtOPKh = (MxOtOPKh + 1) % 256
        GUMQlKMx = (GUMQlKMx + YjYdhIrU[MxOtOPKh]) % 256
        YjYdhIrU[MxOtOPKh], YjYdhIrU[GUMQlKMx] = YjYdhIrU[GUMQlKMx], YjYdhIrU[MxOtOPKh]
        local KvSuNBtw = YjYdhIrU[(YjYdhIrU[MxOtOPKh] + YjYdhIrU[GUMQlKMx]) % 256]
        table.insert(CzTsDIIm, string.char(bit32.bxor(WbbeqWYp, KvSuNBtw)))
    end
    return table.concat(CzTsDIIm)
end

local YjYdhIrU_flat = {}
for _, chunk in ipairs(ickMVUCR) do
    for _, byte in ipairs(chunk) do
        table.insert(YjYdhIrU_flat, byte)
    end
end

local decrypted = lCMeKlbP(YjYdhIrU_flat, JfmHwfjO)
local hhHgEDqn, uSNXaIeI = loadstring(decrypted)
if hhHgEDqn then 
    return hhHgEDqn() 
else 
    warn("[ecco] Boot Error (" .. "hub" .. "): " .. tostring(uSNXaIeI)) 
end
